aiignore: "0.1"
metadata:
  name: Complete
  description: Every rule family and effect
defaults:
  files: deny
  environment: deny
  network: deny
  strings: deny
rules:
  files:
    - {id: file-allow, effect: allow, priority: -1000, operations: [discover], paths: ["/visible/?/**"], except: ["visible/x/private/"]}
    - {id: file-deny, effect: deny, operations: [index, read], paths: ["**/[a-z].pem"]}
    - {id: file-audit, effect: audit, operations: [write], paths: ["audit/**"]}
    - {id: file-read-only, effect: read-only, priority: 1000, operations: [execute], paths: ["bin/**"]}
  environment:
    - {id: env-allow, effect: allow, names: [PUBLIC_*]}
    - {id: env-drop, effect: drop, names: ["*_DROP"]}
    - {id: env-redact, effect: redact, names: ["*_TOKEN"], replacement: "$1/$&/\\"}
    - {id: env-deny, effect: deny, names: [BLOCKED]}
    - {id: env-audit, effect: audit, names: [AUDIT_*], except: [AUDIT_SAFE]}
  network:
    - {id: net-http, effect: allow, urls: ["http://example.com:080/a?/b"]}
    - {id: net-https, effect: deny, urls: ["https://*.example.com/**"]}
    - {id: net-ws, effect: audit, urls: ["ws://127.0.0.1:0/**"]}
    - {id: net-wss, effect: allow, urls: ["wss://[2001:db8::1]:65535/**"]}
  strings:
    - {id: str-allow, effect: allow, scopes: [user_prompt, model_input, model_output], patterns: [{type: literal, value: ok, caseSensitive: false}]}
    - {id: str-deny, effect: deny, scopes: [tool_input, tool_output, file_read], patterns: [{type: glob, value: "*secret?"}]}
    - {id: str-redact, effect: redact, scopes: [file_write, environment_value, network_request], patterns: [{type: regex, value: "KEY-[0-9]+"}], replacement: "$1/$&"}
    - {id: str-audit, effect: audit, scopes: [network_response, log], patterns: [{type: literal, value: audit}], except: [{type: literal, value: fixture}]}

aiignore: "0.1"
metadata: &meta {name: bad}
rules: *meta

aiignore: "0.1"
metadata:
  <<: {name: bad}

aiignore: "0.1"
rules:
  files:
    - {id: same, effect: deny, paths: [x]}
  network:
    - {id: same, effect: deny, urls: ["https://example.com/**"]}
